// ─── FIREBASE REALTIME SYNC ──────────────────────────────────
var _db=null, _ready=false, _saveQueue=[];

function initFirebase(config, onReady){
  // Load Firebase SDK dynamically
  var s1=document.createElement("script");
  s1.src="https://www.gstatic.com/firebasejs/9.23.0/firebase-app-compat.js";
  s1.onload=function(){
    var s2=document.createElement("script");
    s2.src="https://www.gstatic.com/firebasejs/9.23.0/firebase-database-compat.js";
    s2.onload=function(){
      var s3=document.createElement("script");
      s3.src="https://www.gstatic.com/firebasejs/9.23.0/firebase-auth-compat.js";
      s3.onload=function(){
      try{
        var fb=window.firebase;
        if(!fb){console.log("Firebase not available");return;}
        var app=fb.initializeApp(config);
        _db=app.database();
        _ready=true;
        _saveQueue.forEach(function(q){_db.ref(q.p).set(q.d);});
        _saveQueue=[];
        console.log("Firebase ready!");
        // Anonymous sign-in for secure rules
        app.auth().signInAnonymously().then(function(){
          console.log("Signed in anonymously!");
          if(onReady) onReady();
        }).catch(function(e){
          console.log("Auth error:",e);
          if(onReady) onReady();
        });
      }catch(e){console.log("Firebase init error:",e);}
      };
      document.head.appendChild(s3);
    };
    document.head.appendChild(s2);
  };
  document.head.appendChild(s1);
}

function fbSave(path,data){
  if(!_ready||!_db){_saveQueue.push({p:path,d:data});return;}
  try{_db.ref(path).set(data);}catch(e){}
}

function fbReadOnce(path,cb){
  if(!_ready||!_db){cb(null);return;}
  try{
    _db.ref(path).once("value",function(snap){
      var val=snap.val();
      cb(val);
    });
  }catch(e){cb(null);}
}

function fbListen(path,cb){
  if(!_ready||!_db) return;
  try{
    _db.ref(path).on("value",function(snap){
      var v=snap.val();
      if(v!==null&&v!==undefined){
        if(Array.isArray(v)) cb(v);
        else if(typeof v==="object") cb(Object.values(v));
      }
    });
  }catch(e){console.log("fbListen error:",e);}
}



