function Badge(props){
  var m={Paid:{bg:"#dcfce7",c:"#15803d",b:"#bbf7d0"},Pending:{bg:"#fef9c3",c:"#a16207",b:"#fde68a"},Cancelled:{bg:"#fee2e2",c:"#b91c1c",b:"#fecaca"},Active:{bg:"#dbeafe",c:"#1d4ed8",b:"#bfdbfe"},Closed:{bg:"#f1f5f9",c:"#475569",b:"#cbd5e1"}};
  var t=m[props.status]||m.Pending;
  return <span style={{background:t.bg,color:t.c,border:"1px solid "+t.b,padding:"2px 9px",borderRadius:20,fontSize:11,fontWeight:700}}>{props.status}</span>;
}

