function VisaAgentTab(props){
  // Custom visa data now comes from app-level state (Firebase-synced across devices)
  var customCountries=Array.isArray(props.customVisa)?props.customVisa:[];
  // Custom countries override default ones with same id
  var allCountries=VISA_DATA.map(function(c){
    var override=customCountries.find(function(cc){return cc.id===c.id;});
    if(override) return override;
    // Also check children
    if(c.children){
      var newChildren=c.children.map(function(ch){
        var childOverride=customCountries.find(function(cc){return cc.id===ch.id;});
        return childOverride||ch;
      });
      return Object.assign({},c,{children:newChildren});
    }
    return c;
  }).concat(customCountries.filter(function(cc){
    return !VISA_DATA.find(function(d){return d.id===cc.id;})&&
           !VISA_DATA.some(function(d){return d.children&&d.children.find(function(ch){return ch.id===cc.id;});});
  }));

  var [search,setSearch]=useState("");
  var [selId,setSelId]=useState(null);
  var [selSubId,setSelSubId]=useState(null);
  var [activeTab,setActiveTab]=useState("info");
  var [filterOA,setFilterOA]=useState("all");
  var [showAddEdit,setShowAddEdit]=useState(false);
  var [editItem,setEditItem]=useState(null);
  var [showEditCountry,setShowEditCountry]=useState(false);
  var [editingCountry,setEditingCountry]=useState(null);
  var [msgs,setMsgs]=useState([{role:"assistant",content:"Salam! 🌍 Main Olympia Travel ka Visa Assistant hoon.\n\nKisi bhi country ka visa, documents, fees ke baare mein puchein!"}]);
  var [input,setInput]=useState("");
  var [botLoading,setBotLoading]=useState(false);
  var [docType,setDocType]=useState("cover");
  var [docInfo,setDocInfo]=useState({clientName:"",passport:"",destination:"",purpose:"Tourism",duration:"7 days",travelDate:""});
  var [generatedDoc,setGeneratedDoc]=useState("");
  var [docLoading,setDocLoading]=useState(false);
  var msgsRef=useRef(null);

  useEffect(function(){
    if(msgsRef.current) msgsRef.current.scrollTop=msgsRef.current.scrollHeight;
  },[msgs]);

  function saveCustom(updated){
    if(props.setCustomVisa){
      props.setCustomVisa(updated);
    } else {
      try{localStorage.setItem("olympia_custom_visa",JSON.stringify(updated));}catch(e){}
    }
  }

  var filtered=allCountries.filter(function(c){
    var ms=!search||(c.name||"").toLowerCase().includes(search.toLowerCase());
    var mf=filterOA==="all"||(filterOA==="onArrival"&&c.onArrival&&!c.isGroup)||(filterOA==="visa"&&!c.onArrival&&!c.isGroup);
    return ms&&mf;
  });

  var selCountry=allCountries.find(function(c){return c.id===selId;})||null;
  var selSub=selCountry&&selCountry.children?selCountry.children.find(function(c){return c.id===selSubId;})||null:null;
  var displayCountry=selSub||selCountry;

  function generateDoc(){
    if(!docInfo.clientName.trim()||!docInfo.destination.trim()){alert("Client name aur destination zaroor likhein!");return;}
    var n=docInfo.clientName.trim();
    var pp=docInfo.passport.trim()||"[Passport No]";
    var dest=docInfo.destination.trim();
    var purp=docInfo.purpose.trim()||"Tourism";
    var dur=docInfo.duration.trim()||"7 days";
    var tdt=docInfo.travelDate?new Date(docInfo.travelDate).toLocaleDateString("en-PK",{day:"2-digit",month:"long",year:"numeric"}):"[Travel Date]";
    var tod=new Date().toLocaleDateString("en-PK",{day:"2-digit",month:"long",year:"numeric"});
    var ref="OTT/"+new Date().getFullYear()+"/"+Math.floor(Math.random()*9000+1000);
    var sig="\n\n___________________________\nAuthorized Signatory\nOlympia Travel & Tours\nGL No. 6033\nOffice No. SF-18, 2nd Floor, Lavish Mall, Tariq Road, Karachi\nTel: +92-331-2351419 | +92-339-4236777 | +92-323-2255773 | +92-318-3211991\nEmail: bookings@olympiatrvl.com | olympiatraveltours@gmail.com\nWebsite: olympiatrvl.com\nDate: "+tod;
    var doc="";
    if(docType==="cover"){
      doc="Ref No: "+ref+"\nDate: "+tod+"\n\nTo,\nThe Visa Officer\n"+dest+" Embassy / Consulate\nIslamabad, Pakistan\n\nSubject: Cover Letter for Tourist Visa Application - "+n+"\n\nRespected Sir/Madam,\n\nIt is respectfully submitted that Mr./Ms. "+n+", holder of Pakistani Passport No. "+pp+", intends to visit "+dest+" for "+purp+" purposes.\n\nThe applicant is a valued client of Olympia Travel & Tours, a licensed travel agency (GL No. 6033) based in Karachi, Pakistan. We are pleased to confirm that we have made the following travel arrangements:\n\n- Destination: "+dest+"\n- Purpose of Visit: "+purp+"\n- Duration of Stay: "+dur+"\n- Intended Travel Date: "+tdt+"\n\nThe applicant has strong ties to Pakistan and will return upon completion of the visit. All necessary financial arrangements have been made.\n\nWe kindly request the concerned authorities to grant a tourist visa to our client. We assure you that the applicant will abide by all visa conditions and will not overstay.\n\nYours faithfully,"+sig;
    } else if(docType==="bonafide"){
      doc="Ref No: "+ref+"\nDate: "+tod+"\n\nTO WHOM IT MAY CONCERN\n\nBONAFIDE CERTIFICATE / NO OBJECTION CERTIFICATE\n\nThis is to certify that Mr./Ms. "+n+", holder of Pakistani Passport No. "+pp+", is a bonafide traveler and registered client of Olympia Travel & Tours.\n\nThis certificate is issued upon request of the above-mentioned individual who intends to travel to "+dest+" for "+purp+" purposes, commencing from "+tdt+" for a duration of "+dur+".\n\nWe have no objection to the travel of the above-mentioned person. We confirm that:\n1. The applicant is a genuine traveler with no criminal record.\n2. All travel arrangements have been confirmed by our agency.\n3. The applicant will return to Pakistan upon completion of the visit.\n4. This certificate is issued for visa application purposes only.\n\nIssued by:"+sig;
    } else if(docType==="hotel"){
      doc="HOTEL BOOKING CONFIRMATION\n\nBooking Reference: "+ref+"\nDate of Issue: "+tod+"\n\nGuest Name: "+n+"\nPassport No.: "+pp+"\nDestination: "+dest+"\nCheck-in Date: "+tdt+"\nDuration of Stay: "+dur+"\nCheck-out Date: [As per itinerary]\n\nHotel: [Hotel Name, "+dest+"]\nRoom Type: Standard / Deluxe Room\nMeal Plan: Bed & Breakfast\nTotal Amount: [As per package]\nPayment Status: CONFIRMED\n\nThis booking has been confirmed by Olympia Travel & Tours on behalf of the guest.\n\n"+sig.trim();
    } else if(docType==="ticket"){
      doc="FLIGHT BOOKING CONFIRMATION\n\nBooking Reference: "+ref+"\nDate of Issue: "+tod+"\n\nPassenger Name: "+n+"\nPassport No.: "+pp+"\nNationality: Pakistani\n\nOUTBOUND FLIGHT:\nRoute: Karachi (KHI) to "+dest+"\nDate: "+tdt+"\nFlight: [Airline] [Flight No.]\nClass: Economy\nStatus: CONFIRMED\n\nRETURN FLIGHT:\nRoute: "+dest+" to Karachi (KHI)\nDate: [After "+dur+"]\nFlight: [Airline] [Flight No.]\nClass: Economy\nStatus: CONFIRMED\n\nTicket Amount: [As per airline]\nPayment Status: PAID\n\nThis booking has been confirmed by Olympia Travel & Tours. Please carry this confirmation with your valid passport.\n\n"+sig.trim();
    }
    setGeneratedDoc(doc);
  }

    function sendMsg(){
    if(!input.trim()||botLoading) return;
    var um={role:"user",content:input.trim()};
    var nm=msgs.concat([um]);
    setMsgs(nm);setInput("");setBotLoading(true);
    fetch("https://api.anthropic.com/v1/messages",{
      method:"POST",
      headers:{
        "Content-Type":"application/json",
        "anthropic-dangerous-direct-browser-access":"true"
      },
      body:JSON.stringify({
        model:"claude-sonnet-4-6",max_tokens:1000,
        system:"You are a visa expert for Olympia Travel & Tours Karachi. Answer in Roman Urdu + English. Help about visa requirements, processing, fees, tips for Pakistan passport holders. Agency: 03312351419.",
        messages:nm
      })
    }).then(function(r){return r.json();}).then(function(d){
      setMsgs(nm.concat([{role:"assistant",content:d.content&&d.content[0]?d.content[0].text:"Sorry, try again."}]));
      setBotLoading(false);
    }).catch(function(){
      setMsgs(nm.concat([{role:"assistant",content:"Connection error. Please try again."}]));
      setBotLoading(false);
    });
  }

  function printCountry(c){
    if(!c) return;
    var reqLines=(c.requirements||"").split("\n").filter(Boolean);
    var reqHtml=reqLines.map(function(r){return "<li style='margin-bottom:5px'>"+r+"</li>";}).join("");
    var w=window.open("","_blank");
    w.document.write("<!DOCTYPE html><html><head><title>"+c.name+"</title><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Segoe UI',sans-serif;padding:0}.hdr{background:linear-gradient(135deg,#16a34a,#059669);color:#fff;padding:18px 24px;display:flex;align-items:center;justify-content:space-between}.a1{font-size:16px;font-weight:900}.a2{font-size:9px;opacity:.85;margin-top:1px}.a3{font-size:10px;opacity:.85;margin-top:4px;line-height:1.6}.badge{background:rgba(255,255,255,.2);border-radius:9px;padding:8px 14px;text-align:center}.body{padding:18px 24px}.grid{display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;margin-bottom:14px}.card{background:#f0fdf4;border:1.5px solid #bbf7d0;border-radius:8px;padding:10px;text-align:center}.cl{font-size:8px;font-weight:700;color:#16a34a;text-transform:uppercase;margin-bottom:2px}.cv{font-size:11px;font-weight:800}.st{font-size:10px;font-weight:800;color:#16a34a;text-transform:uppercase;margin-bottom:7px;padding-bottom:4px;border-bottom:2px solid #bbf7d0}ul{padding-left:14px;font-size:11px;line-height:1.8;color:#374151;margin-bottom:12px}.nt{background:#fefce8;border:1.5px solid #fde68a;border-radius:7px;padding:9px;font-size:10px;color:#92400e;margin-bottom:12px}.pay{background:#f0fdf4;border:1px solid #bbf7d0;border-radius:7px;padding:9px;font-size:10px;line-height:1.9}.ft{text-align:center;color:#9ca3af;font-size:9px;margin-top:10px;padding-top:7px;border-top:1px dashed #e5e7eb}.wm{position:fixed;top:50%;left:50%;transform:translate(-50%,-50%) rotate(-35deg);font-size:65px;font-weight:900;color:rgba(22,163,74,.04);pointer-events:none;white-space:nowrap}@media print{*{-webkit-print-color-adjust:exact!important}}</style></head><body>"
    +"<div class='wm'>OLYMPIA TRAVEL</div>"
    +"<div class='hdr'><div><div class='a1'>Olympia Travel & Tours</div><div class='a2'>GL No. 6033 | Visa & Travel Consultants</div><div class='a3'>📍 SF-18, 2nd Floor, Lavish Mall, Tariq Road, Karachi<br>📞 +92-331-2351419 | +92-339-4236777 | +92-323-2255773 | +92-318-3211991</div></div>"
    +"<div class='badge'><div style='font-size:28px'>"+c.flag+"</div><div style='font-weight:800;font-size:13px'>"+c.name+"</div></div></div>"
    +"<div class='body'>"
    +"<div class='grid'>"
    +"<div class='card'><div class='cl'>Visa Type</div><div class='cv'>"+c.type+"</div></div>"
    +"<div class='card'><div class='cl'>Agency Fee</div><div class='cv'>"+(Number(c.fees||0)>0?"PKR "+Number(c.fees).toLocaleString():"FREE")+"</div></div>"
    +"<div class='card'><div class='cl'>Processing</div><div class='cv'>"+c.processing+"</div></div>"
    +"</div>"
    +"<div class='st'>📋 Required Documents</div><ul>"+reqHtml+"</ul>"
    +"<div class='st'>ℹ️ Important Notes</div><div class='nt'>"+c.notes+"</div>"
    +"<div class='st'>💳 Payment Details</div>"
    +"<div class='pay'>JazzCash / EasyPaisa / SadaPay / NayaPay: <b>03312351419</b> (Dawood Shoukat)<br>Bank Alfalah A/C: <b>55875002428885</b> | IBAN: <b>PK84ALFH5587005002428885</b><br>Bank Al Habib A/C: <b>10070981032324010</b> | IBAN: <b>PK32BAHL1007098103232401</b><br>Account Title: <b>M/S Olympia Travel And Tours</b></div>"
    +"</div><div class='ft'>Reference only. Requirements may change. Printed: "+new Date().toLocaleDateString("en-PK")+"</div>"
    +"</body></html>");
    w.document.close();setTimeout(function(){w.print();},400);
  }

  var emptyForm={id:"",name:"",flag:"🌍",fees:"",processing:"",validity:"",type:"Tourist",onArrival:false,requirements:"",notes:""};
  var [form,setForm]=useState(emptyForm);

  function saveForm(){
    if(!form.name.trim()){alert("Country name likhein!");return;}
    var entry=Object.assign({},form,{id:form.id||("cu"+Date.now()),fees:form.fees||"0"});
    var updated=editItem?customCountries.map(function(c){return c.id===entry.id?entry:c;}):customCountries.concat([entry]);
    saveCustom(updated);setShowAddEdit(false);setEditItem(null);setSelId(entry.id);
  }

  return(
    <div>
      {/* Header */}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12,flexWrap:"wrap",gap:8}}>
        <div>
          <h2 style={{margin:0,fontSize:16,fontWeight:800,color:C.accent}}>🌍 Visa Center</h2>
          <div style={{color:C.muted,fontSize:11,marginTop:2}}>{allCountries.length} entries — Click country to see details</div>
        </div>
        <div style={{display:"flex",gap:6}}>
          {[["info","🌍 Countries"],["bot","🤖 AI Bot"],["docs","📄 Documents"],["manage","⚙️ Manage"]].map(function(t){return(
            <button key={t[0]} onClick={function(){setActiveTab(t[0]);}}
              style={{padding:"7px 13px",border:"1.5px solid "+(activeTab===t[0]?C.accent:C.border),borderRadius:8,background:activeTab===t[0]?C.accent:"#fff",color:activeTab===t[0]?"#fff":C.muted,fontWeight:700,cursor:"pointer",fontSize:11}}>
              {t[1]}
            </button>
          );})}
        </div>
      </div>

      {/* INFO TAB */}
      {activeTab==="info"&&(
        <div>
          <div style={{display:"flex",gap:8,marginBottom:12,flexWrap:"wrap",alignItems:"center"}}>
            <input value={search} onChange={function(e){setSearch(e.target.value);setSelId(null);setSelSubId(null);}}
              placeholder="🔍 Search..."
              style={{flex:1,minWidth:150,background:"#fff",border:"1.5px solid "+C.accent,borderRadius:8,padding:"8px 12px",fontSize:13,outline:"none"}}/>
            {[["all","All"],["onArrival","✅ Free/On Arrival"],["visa","📋 Visa Required"]].map(function(f){return(
              <button key={f[0]} onClick={function(){setFilterOA(f[0]);setSelId(null);setSelSubId(null);}}
                style={{padding:"7px 12px",border:"1.5px solid "+C.border,borderRadius:8,background:filterOA===f[0]?C.accent:"#fff",color:filterOA===f[0]?"#fff":C.muted,fontWeight:700,cursor:"pointer",fontSize:11}}>
                {f[1]}
              </button>
            );})}
          </div>

          {/* Countries grid */}
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(130px,1fr))",gap:8,marginBottom:14}}>
            {filtered.map(function(c){
              var isSel=selId===c.id;
              return(
                <div key={c.id} onClick={function(){setSelId(isSel?null:c.id);setSelSubId(null);}}
                  style={{background:isSel?"#f0fdf4":"#fff",border:"2px solid "+(isSel?"#16a34a":c.isGroup?"#a5f3fc":C.border),borderRadius:10,padding:10,cursor:"pointer",textAlign:"center",position:"relative"}}>
                  {c.isGroup&&<div style={{position:"absolute",top:4,right:6,fontSize:9,color:"#0891b2",fontWeight:700}}>{c.children.length}▼</div>}
                  <div style={{fontSize:24,marginBottom:3}}>{c.flag}</div>
                  <div style={{fontWeight:800,fontSize:11,color:"#1f2937",marginBottom:2,lineHeight:1.2}}>{c.name}</div>
                  {c.isGroup
                    ?<div style={{background:"#e0f2fe",color:"#0891b2",borderRadius:20,fontSize:9,fontWeight:700,padding:"1px 6px"}}>Click to expand</div>
                    :c.onArrival
                      ?<div style={{background:"#dcfce7",color:"#16a34a",borderRadius:20,fontSize:9,fontWeight:700,padding:"1px 6px"}}>✅ Free/On Arrival</div>
                      :<div style={{color:"#dc2626",fontSize:10,fontWeight:700}}>{Number(c.fees||0)>0?"PKR "+Number(c.fees).toLocaleString():"Free"}</div>
                  }
                </div>
              );
            })}
          </div>

          {/* Sub countries (for groups like Schengen) */}
          {selCountry&&selCountry.isGroup&&(
            <div style={{background:"#f0f9ff",border:"2px solid #a5f3fc",borderRadius:14,padding:16,marginBottom:14}}>
              <div style={{fontWeight:800,color:"#0891b2",fontSize:14,marginBottom:10}}>
                {selCountry.flag} {selCountry.name} — Select Country
              </div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(140px,1fr))",gap:8}}>
                {selCountry.children.map(function(ch){
                  var isSelSub=selSubId===ch.id;
                  return(
                    <div key={ch.id} onClick={function(){setSelSubId(isSelSub?null:ch.id);}}
                      style={{background:isSelSub?"#dbeafe":"#fff",border:"2px solid "+(isSelSub?"#3b82f6":"#e0f2fe"),borderRadius:9,padding:"10px",cursor:"pointer",textAlign:"center"}}>
                      <div style={{fontSize:22,marginBottom:3}}>{ch.flag}</div>
                      <div style={{fontWeight:700,fontSize:11}}>{ch.name}</div>
                      <div style={{color:"#6b7280",fontSize:10}}>{ch.processing}</div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* Detail panel */}
          {displayCountry&&!displayCountry.isGroup&&(
            <div style={{background:"#fff",border:"2px solid #16a34a",borderRadius:14,padding:18,boxShadow:"0 4px 16px rgba(0,0,0,.08)"}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:14,flexWrap:"wrap",gap:8}}>
                <div style={{display:"flex",alignItems:"center",gap:10}}>
                  <span style={{fontSize:36}}>{displayCountry.flag}</span>
                  <div>
                    <div style={{fontWeight:900,fontSize:17}}>{displayCountry.name}</div>
                    <div style={{color:C.muted,fontSize:12}}>{displayCountry.type}</div>
                    {displayCountry.onArrival&&<span style={{background:"#dcfce7",color:"#16a34a",padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700}}>✅ Free / On Arrival</span>}
                  </div>
                </div>
                <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                  <button onClick={function(){printCountry(displayCountry);}}
                    style={{background:"#16a34a",color:"#fff",border:"none",borderRadius:8,padding:"8px 14px",fontWeight:800,cursor:"pointer",fontSize:12}}>🖨️ Print</button>
                  <button onClick={function(){
                    setEditingCountry(Object.assign({},displayCountry));
                    setShowEditCountry(true);
                  }} style={{background:"#eff6ff",border:"1px solid #bfdbfe",color:"#1d4ed8",borderRadius:8,padding:"8px 14px",fontWeight:700,cursor:"pointer",fontSize:12}}>✏️ Edit</button>
                  <button onClick={function(){setSelId(null);setSelSubId(null);}}
                    style={{background:"#fee2e2",border:"1px solid #fecaca",color:"#dc2626",borderRadius:8,padding:"8px 10px",cursor:"pointer",fontSize:12,fontWeight:700}}>✕</button>
                </div>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10,marginBottom:14}}>
                {[["💰 Fee",Number(displayCountry.fees||0)>0?"PKR "+Number(displayCountry.fees).toLocaleString():"FREE"],["⏱️ Processing",displayCountry.processing],["📅 Validity",displayCountry.validity]].map(function(cc){return(
                  <div key={cc[0]} style={{background:"#f0fdf4",border:"1.5px solid #bbf7d0",borderRadius:9,padding:10,textAlign:"center"}}>
                    <div style={{fontSize:9,fontWeight:700,color:"#16a34a",textTransform:"uppercase",marginBottom:3}}>{cc[0]}</div>
                    <div style={{fontSize:12,fontWeight:800}}>{cc[1]}</div>
                  </div>
                );})}
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
                <div>
                  <div style={{fontWeight:800,color:"#16a34a",fontSize:11,textTransform:"uppercase",marginBottom:8,borderBottom:"2px solid #bbf7d0",paddingBottom:5}}>📋 Requirements</div>
                  <ul style={{paddingLeft:16,margin:0}}>
                    {(displayCountry.requirements||"").split("\n").filter(Boolean).map(function(r,i){return(
                      <li key={i} style={{fontSize:12,color:"#374151",marginBottom:4,lineHeight:1.5}}>{r}</li>
                    );})}
                  </ul>
                </div>
                <div>
                  <div style={{fontWeight:800,color:"#16a34a",fontSize:11,textTransform:"uppercase",marginBottom:8,borderBottom:"2px solid #bbf7d0",paddingBottom:5}}>ℹ️ Notes</div>
                  <div style={{background:"#fefce8",border:"1.5px solid #fde68a",borderRadius:8,padding:10,fontSize:12,color:"#92400e",lineHeight:1.6}}>{displayCountry.notes}</div>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {/* Edit Country Modal */}
      {showEditCountry&&editingCountry&&(
        <Modal title={"✏️ Edit: "+editingCountry.name} onClose={function(){setShowEditCountry(false);setEditingCountry(null);}}>
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
            {[["name","Country Name"],["flag","Flag Emoji"],["fees","Agency Fee (PKR)"],["processing","Processing Time"],["validity","Validity"],["type","Visa Type"]].map(function(fl){
              var fk=fl[0];
              return(
                <div key={fk}>
                  <label style={{display:"block",fontSize:9,fontWeight:700,color:C.accent,textTransform:"uppercase",marginBottom:3}}>{fl[1]}</label>
                  <input value={editingCountry[fk]||""} onChange={function(ev){var v=ev.target.value;setEditingCountry(function(p){var n=Object.assign({},p);n[fk]=v;return n;});}}
                    style={{width:"100%",background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:7,padding:"8px",fontSize:13,outline:"none",boxSizing:"border-box"}}/>
                </div>
              );
            })}
            <div>
              <div style={{fontSize:9,fontWeight:700,color:C.accent,textTransform:"uppercase",marginBottom:5}}>Visa Status</div>
              <div style={{display:"flex",gap:0,border:"1.5px solid "+C.border,borderRadius:8,overflow:"hidden"}}>
                <button onClick={function(){setEditingCountry(function(p){return Object.assign({},p,{onArrival:false});});}}
                  style={{flex:1,padding:"9px 0",border:"none",background:!editingCountry.onArrival?"#dc2626":"#fff",color:!editingCountry.onArrival?"#fff":"#6b7280",fontWeight:700,cursor:"pointer",fontSize:12}}>📋 Visa Required</button>
                <button onClick={function(){setEditingCountry(function(p){return Object.assign({},p,{onArrival:true});});}}
                  style={{flex:1,padding:"9px 0",border:"none",background:editingCountry.onArrival?"#16a34a":"#fff",color:editingCountry.onArrival?"#fff":"#6b7280",fontWeight:700,cursor:"pointer",fontSize:12}}>✅ Free/On Arrival</button>
              </div>
            </div>
            <div>
              <label style={{display:"block",fontSize:9,fontWeight:700,color:C.accent,textTransform:"uppercase",marginBottom:3}}>Requirements (1 per line)</label>
              <textarea value={editingCountry.requirements||""} onChange={function(e){var v=e.target.value;setEditingCountry(function(p){return Object.assign({},p,{requirements:v});});}} rows={6}
                style={{width:"100%",background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:7,padding:"8px",fontSize:12,outline:"none",resize:"vertical",boxSizing:"border-box"}}/>
            </div>
            <div>
              <label style={{display:"block",fontSize:9,fontWeight:700,color:C.accent,textTransform:"uppercase",marginBottom:3}}>Notes</label>
              <textarea value={editingCountry.notes||""} onChange={function(e){var v=e.target.value;setEditingCountry(function(p){return Object.assign({},p,{notes:v});});}} rows={3}
                style={{width:"100%",background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:7,padding:"8px",fontSize:12,outline:"none",resize:"vertical",boxSizing:"border-box"}}/>
            </div>
            <button onClick={function(){
              // Save to customCountries (override default)
              var existing=customCountries.findIndex(function(c){return c.id===editingCountry.id;});
              var updated;
              if(existing>=0){
                updated=customCountries.map(function(c){return c.id===editingCountry.id?editingCountry:c;});
              } else {
                updated=customCountries.concat([editingCountry]);
              }
              saveCustom(updated);
              setShowEditCountry(false);
              setEditingCountry(null);
            }} style={{background:C.accent,color:"#fff",border:"none",borderRadius:8,padding:"11px 0",fontWeight:800,cursor:"pointer",fontSize:14}}>
              💾 Save Changes
            </button>
          </div>
        </Modal>
      )}

      {/* BOT TAB */}
      {activeTab==="bot"&&(
        <div style={{background:"#fff",border:"1.5px solid "+C.border,borderRadius:14,overflow:"hidden"}}>
          <div ref={msgsRef} style={{height:420,overflowY:"auto",padding:16,display:"flex",flexDirection:"column",gap:10}}>
            {msgs.map(function(m,i){return(
              <div key={i} style={{display:"flex",justifyContent:m.role==="user"?"flex-end":"flex-start"}}>
                <div style={{maxWidth:"78%",background:m.role==="user"?C.accent:"#f3f4f6",color:m.role==="user"?"#fff":"#1f2937",padding:"10px 14px",borderRadius:m.role==="user"?"14px 14px 4px 14px":"14px 14px 14px 4px",fontSize:13,lineHeight:1.5,whiteSpace:"pre-wrap"}}>
                  {m.content}
                </div>
              </div>
            );})}
            {botLoading&&<div style={{display:"flex"}}><div style={{background:"#f3f4f6",padding:"10px 14px",borderRadius:"14px 14px 14px 4px",fontSize:13,color:C.muted}}>Typing...</div></div>}
          </div>
          <div style={{borderTop:"1.5px solid "+C.border,padding:12,display:"flex",gap:8}}>
            <input value={input} onChange={function(e){setInput(e.target.value);}}
              onKeyDown={function(e){if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();sendMsg();}}}
              placeholder="Visa sawaal puchein... (Enter to send)"
              style={{flex:1,background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:9,padding:"10px 14px",fontSize:13,outline:"none"}}/>
            <button onClick={sendMsg} disabled={botLoading}
              style={{background:C.accent,color:"#fff",border:"none",borderRadius:9,padding:"10px 18px",fontWeight:800,cursor:"pointer",fontSize:13,opacity:botLoading?0.6:1}}>Send</button>
            <button onClick={function(){setMsgs([{role:"assistant",content:"Salam! 🌍 Main Olympia Travel ka Visa Assistant hoon.\n\nKisi bhi country ka visa ke baare mein puchein!"}]);}}
              style={{background:"#f3f4f6",border:"1px solid "+C.border,color:C.muted,borderRadius:9,padding:"10px 10px",cursor:"pointer",fontSize:12}}>🗑</button>
          </div>
          <div style={{padding:"8px 12px 10px",borderTop:"1px solid "+C.border,display:"flex",gap:6,flexWrap:"wrap"}}>
            {["UAE visa?","Schengen documents?","UK visa tips?","Best countries for Pakistan?","Turkey e-visa?"].map(function(q){return(
              <button key={q} onClick={function(){setInput(q);}}
                style={{background:C.accentSoft,border:"1px solid "+C.border,color:C.accent,borderRadius:20,padding:"4px 10px",cursor:"pointer",fontSize:11,fontWeight:600}}>{q}</button>
            );})}
          </div>
        </div>
      )}

      {/* DOCS TAB */}
      {activeTab==="docs"&&(
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
          <div style={{background:"#fff",border:"1.5px solid "+C.border,borderRadius:14,padding:16}}>
            <div style={{fontWeight:800,color:C.accent,fontSize:14,marginBottom:12}}>📄 Document Details</div>
            <div style={{display:"flex",flexDirection:"column",gap:9}}>
              <div>
                <label style={{display:"block",fontSize:9,fontWeight:700,color:C.accent,textTransform:"uppercase",marginBottom:3}}>Document Type</label>
                <select value={docType} onChange={function(e){setDocType(e.target.value);setGeneratedDoc("");}}
                  style={{width:"100%",background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:7,padding:"8px",fontSize:12,outline:"none"}}>
                  <option value="cover">✉️ Cover Letter</option>
                  <option value="bonafide">📋 Bonafide / NOC Letter</option>
                  <option value="hotel">🏨 Hotel Booking Confirmation</option>
                  <option value="ticket">✈️ Flight Ticket Confirmation</option>
                </select>
              </div>
              {[["clientName","Client Full Name *"],["passport","Passport Number"],["destination","Destination Country *"],["purpose","Purpose of Travel"],["duration","Duration (e.g. 7 days)"],["travelDate","Travel Date"]].map(function(fl){
                var fkey=fl[0];
                return(
                <div key={fkey}>
                  <label style={{display:"block",fontSize:9,fontWeight:700,color:C.accent,textTransform:"uppercase",marginBottom:3}}>{fl[1]}</label>
                  <input value={docInfo[fkey]||""} onChange={function(ev){
                    var val=ev.target.value;
                    setDocInfo(function(prev){
                      var next=Object.assign({},prev);
                      next[fkey]=val;
                      return next;
                    });
                  }}
                    style={{width:"100%",background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:7,padding:"8px",fontSize:12,outline:"none",boxSizing:"border-box"}}/>
                </div>
              );})}
              <button onClick={generateDoc} disabled={docLoading}
                style={{background:C.accent,color:"#fff",border:"none",borderRadius:8,padding:"11px 0",fontWeight:800,cursor:"pointer",fontSize:13,marginTop:4,opacity:docLoading?0.6:1}}>
                {docLoading?"⏳ Generating...":"🤖 Generate Document"}
              </button>
            </div>
          </div>
          <div style={{background:"#fff",border:"1.5px solid "+C.border,borderRadius:14,padding:16,display:"flex",flexDirection:"column"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
              <div style={{fontWeight:800,color:C.accent,fontSize:14}}>📄 Generated Document</div>
              {generatedDoc&&(
                <div style={{display:"flex",gap:6}}>
                  <button onClick={function(){navigator.clipboard&&navigator.clipboard.writeText(generatedDoc);}}
                    style={{background:C.accentSoft,border:"1px solid "+C.border,color:C.accent,borderRadius:7,padding:"5px 10px",cursor:"pointer",fontSize:11,fontWeight:700}}>📋 Copy</button>
                  <button onClick={function(){
                    var w=window.open("","_blank");
                    w.document.write("<!DOCTYPE html><html><head><title>Document</title><style>body{font-family:'Times New Roman',serif;padding:50px;max-width:800px;margin:0 auto;font-size:13px;line-height:2}pre{white-space:pre-wrap;font-family:inherit}@media print{*{-webkit-print-color-adjust:exact!important}}</style></head><body><pre>"+generatedDoc+"</pre></body></html>");
                    w.document.close();setTimeout(function(){w.print();},400);
                  }} style={{background:C.accent,color:"#fff",border:"none",borderRadius:7,padding:"5px 10px",cursor:"pointer",fontSize:11,fontWeight:700}}>🖨️ Print</button>
                </div>
              )}
            </div>
            <textarea readOnly value={generatedDoc||(docLoading?"Generating...":"Document yahan aayega...")}
              style={{flex:1,minHeight:400,background:generatedDoc?"#f9fafb":"#f3f4f6",border:"1.5px solid "+C.border,borderRadius:8,padding:12,fontSize:12,resize:"none",outline:"none",lineHeight:1.7,color:generatedDoc?"#1f2937":C.muted,fontFamily:"'Segoe UI',sans-serif"}}/>
          </div>
        </div>
      )}

      {/* MANAGE TAB */}
      {activeTab==="manage"&&(
        <div>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
            <div style={{color:C.muted,fontSize:12}}>Apni custom countries add/edit karein</div>
            <button onClick={function(){setForm(emptyForm);setEditItem(null);setShowAddEdit(true);}}
              style={{background:C.accent,color:"#fff",border:"none",borderRadius:8,padding:"8px 16px",fontWeight:800,cursor:"pointer",fontSize:13}}>+ Add Country</button>
          </div>

          {showAddEdit&&(
            <div style={{background:"#fff",border:"2px solid "+C.accent,borderRadius:14,padding:18,marginBottom:14}}>
              <div style={{fontWeight:800,color:C.accent,fontSize:14,marginBottom:14}}>{editItem?"✏️ Edit":"+ New Country"}</div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:10}}>
                {[["name","Country Name *"],["flag","Flag Emoji"],["fees","Agency Fee (PKR)"],["processing","Processing Time"],["validity","Validity"],["type","Visa Type"]].map(function(fl){
                  var fkey=fl[0];
                  return(
                  <div key={fkey}>
                    <label style={{display:"block",fontSize:9,fontWeight:700,color:C.accent,textTransform:"uppercase",marginBottom:3}}>{fl[1]}</label>
                    <input value={form[fkey]||""} onChange={function(ev){
                      var val=ev.target.value;
                      setForm(function(prev){var next=Object.assign({},prev);next[fkey]=val;return next;});
                    }}
                      style={{width:"100%",background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:7,padding:"8px",fontSize:13,outline:"none",boxSizing:"border-box"}}/>
                  </div>
                );})}
              </div>
              <div style={{marginBottom:10}}>
                <div style={{fontSize:9,fontWeight:700,color:C.accent,textTransform:"uppercase",marginBottom:5}}>Visa Status (Pakistan Passport)</div>
                <div style={{display:"flex",gap:0,border:"1.5px solid "+C.border,borderRadius:8,overflow:"hidden"}}>
                  <button onClick={function(){setForm(function(p){return Object.assign({},p,{onArrival:false});});}}
                    style={{flex:1,padding:"9px 0",border:"none",background:!form.onArrival?"#dc2626":"#fff",color:!form.onArrival?"#fff":"#6b7280",fontWeight:700,cursor:"pointer",fontSize:12}}>📋 Visa Required</button>
                  <button onClick={function(){setForm(function(p){return Object.assign({},p,{onArrival:true});});}}
                    style={{flex:1,padding:"9px 0",border:"none",background:form.onArrival?"#16a34a":"#fff",color:form.onArrival?"#fff":"#6b7280",fontWeight:700,cursor:"pointer",fontSize:12}}>✅ Free / On Arrival</button>
                </div>
              </div>
              <div style={{marginBottom:10}}>
                <label style={{display:"block",fontSize:9,fontWeight:700,color:C.accent,textTransform:"uppercase",marginBottom:3}}>Requirements (ek line = ek requirement)</label>
                <textarea value={form.requirements||""} onChange={function(e){setForm(function(p){return Object.assign({},p,{requirements:e.target.value});});}} rows={6}
                  style={{width:"100%",background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:7,padding:"8px",fontSize:12,outline:"none",resize:"vertical",boxSizing:"border-box"}}/>
              </div>
              <div style={{marginBottom:14}}>
                <label style={{display:"block",fontSize:9,fontWeight:700,color:C.accent,textTransform:"uppercase",marginBottom:3}}>Notes</label>
                <textarea value={form.notes||""} onChange={function(e){setForm(function(p){return Object.assign({},p,{notes:e.target.value});});}} rows={3}
                  style={{width:"100%",background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:7,padding:"8px",fontSize:12,outline:"none",resize:"vertical",boxSizing:"border-box"}}/>
              </div>
              <div style={{display:"flex",gap:8}}>
                <button onClick={saveForm}
                  style={{flex:2,background:C.accent,color:"#fff",border:"none",borderRadius:8,padding:"11px 0",fontWeight:800,cursor:"pointer",fontSize:14}}>💾 Save</button>
                <button onClick={function(){setShowAddEdit(false);setEditItem(null);}}
                  style={{flex:1,background:"#f3f4f6",border:"1px solid "+C.border,color:C.muted,borderRadius:8,padding:"11px 0",fontWeight:700,cursor:"pointer"}}>Cancel</button>
              </div>
            </div>
          )}

          <div style={{fontWeight:700,color:C.accent,fontSize:12,marginBottom:8}}>Custom Countries ({customCountries.length})</div>
          {customCountries.length===0&&<div style={{color:C.muted,fontSize:13,padding:"20px",textAlign:"center",background:"#f9fafb",borderRadius:10}}>Koi custom country nahi — "+ Add Country" se add karein</div>}
          {customCountries.map(function(c){return(
            <div key={c.id} style={{background:"#fff",border:"1.5px solid "+C.border,borderRadius:10,padding:"12px 14px",display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
              <div style={{display:"flex",alignItems:"center",gap:10}}>
                <span style={{fontSize:22}}>{c.flag}</span>
                <div>
                  <div style={{fontWeight:700,fontSize:13}}>{c.name}</div>
                  <div style={{color:C.muted,fontSize:11}}>{c.onArrival?"✅ Free":"PKR "+(Number(c.fees||0).toLocaleString())} | {c.processing}</div>
                </div>
              </div>
              <div style={{display:"flex",gap:6}}>
                <button onClick={function(){setForm(Object.assign({},c));setEditItem(c);setShowAddEdit(true);}}
                  style={{background:"#fffbeb",border:"1px solid #fde68a",color:C.gold,borderRadius:6,padding:"5px 10px",cursor:"pointer",fontSize:11,fontWeight:700}}>✏️ Edit</button>
                <button onClick={function(){if(window.confirm("Delete?"))saveCustom(customCountries.filter(function(x){return x.id!==c.id;}));}}
                  style={{background:"#fee2e2",border:"1px solid #fecaca",color:"#dc2626",borderRadius:6,padding:"5px 10px",cursor:"pointer",fontSize:11,fontWeight:700}}>🗑</button>
              </div>
            </div>
          );})}
        </div>
      )}
    </div>
  );
}


// ─── USER EDITOR COMPONENT ─────────────────────────────────
function UserEditor(ep){
  var u=ep.user;
  var saveUser=ep.saveUser;
  var delStaff=ep.delStaff;
  var sections=ep.sections||[];
  var sectionLabels=ep.sectionLabels||{};
  var [name,setName]=useState(u.name);
  var [uid_val,setUidVal]=useState(u.id);
  var [pass,setPass]=useState(u.password);
  var [tabs,setTabs]=useState(Array.isArray(u.tabs)?u.tabs:[]);

  function toggleTab(id){
    setTabs(tabs.includes(id)?tabs.filter(function(t){return t!==id;}):tabs.concat([id]));
  }

  return(
    <div style={{background:"#fff",border:"2px solid "+C.accent,borderRadius:14,padding:18,marginBottom:14}}>
      <div style={{fontWeight:800,color:C.accent,fontSize:14,marginBottom:12}}>
        ✏️ Editing: {u.name}
        {u.role!=="admin"&&<button onClick={function(){delStaff(u.id);}} style={{float:"right",background:C.redBg,border:"1px solid #fecaca",color:C.red,borderRadius:6,padding:"3px 10px",cursor:"pointer",fontSize:11,fontWeight:700}}>Delete Staff</button>}
      </div>

      <div style={{display:"flex",gap:10,marginBottom:12,flexWrap:"wrap"}}>
        <div style={{flex:1,minWidth:150}}>
          <label style={{display:"block",color:C.accent,fontSize:10,fontWeight:700,marginBottom:4,textTransform:"uppercase"}}>Name</label>
          <input value={name} onChange={function(e){setName(e.target.value);}} disabled={u.role==="admin"}
            style={{width:"100%",background:u.role==="admin"?"#f3f4f6":C.accentSoft,border:"1.5px solid "+C.border,borderRadius:8,padding:"8px 10px",fontSize:13,outline:"none",boxSizing:"border-box"}}/>
        </div>
        <div style={{flex:1,minWidth:150}}>
          <label style={{display:"block",color:C.accent,fontSize:10,fontWeight:700,marginBottom:4,textTransform:"uppercase"}}>Login ID <span style={{color:C.muted,fontWeight:400,textTransform:"none"}}>(change kar sakte hain)</span></label>
          <input value={uid_val} onChange={function(e){setUidVal(e.target.value.replace(/ /g,""));}} disabled={u.role==="admin"}
            style={{width:"100%",background:u.role==="admin"?"#f3f4f6":C.accentSoft,border:"1.5px solid "+C.border,borderRadius:8,padding:"8px 10px",fontSize:13,outline:"none",boxSizing:"border-box",fontFamily:"monospace"}}/>
        </div>
        <div style={{flex:1,minWidth:150}}>
          <label style={{display:"block",color:C.accent,fontSize:10,fontWeight:700,marginBottom:4,textTransform:"uppercase"}}>Password</label>
          <input value={pass} onChange={function(e){setPass(e.target.value);}}
            style={{width:"100%",background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:8,padding:"8px 10px",fontSize:13,outline:"none",boxSizing:"border-box",fontFamily:"monospace"}}/>
        </div>
      </div>

      {u.role!=="admin"&&(
        <div>
          <label style={{display:"block",color:C.accent,fontSize:10,fontWeight:700,marginBottom:8,textTransform:"uppercase"}}>
            Access — Kaunse Sections Dikhein
          </label>
          <div style={{display:"flex",flexWrap:"wrap",gap:8,marginBottom:12}}>
            {sections.map(function(s){
              var isOn=tabs.includes(s.id);
              return(
                <button key={s.id} onClick={function(){toggleTab(s.id);}}
                  style={{padding:"7px 14px",border:"2px solid "+(isOn?C.accent:C.border),borderRadius:9,background:isOn?C.accent:"#fff",color:isOn?"#fff":C.muted,fontWeight:700,cursor:"pointer",fontSize:12,transition:"all .15s"}}>
                  {isOn?"✅ ":"⬜ "}{s.label}
                </button>
              );
            })}
          </div>
          <div style={{background:C.accentSoft,borderRadius:8,padding:"8px 12px",fontSize:11,color:C.muted,marginBottom:12}}>
            ✅ Selected: {tabs.map(function(t){return sectionLabels[t]||t;}).join(", ")||"Koi nahi"}
          </div>
        </div>
      )}

      {u.role==="admin"&&(
        <div style={{background:"#f0fdf4",borderRadius:8,padding:"8px 12px",fontSize:11,color:C.accent,marginBottom:12}}>
          🔑 Admin — Hamesha sab sections ka access hoga
        </div>
      )}

      <div style={{display:"flex",gap:8}}>
        <button onClick={function(){saveUser(Object.assign({},u,{id:u.role==="admin"?u.id:(uid_val||u.id),name:name,password:pass,tabs:u.role==="admin"?null:tabs}),u.id);}}
          style={{flex:2,background:C.accent,color:"#fff",border:"none",borderRadius:8,padding:"10px 0",fontWeight:800,cursor:"pointer",fontSize:13}}>
          💾 Save Changes
        </button>
        <button onClick={function(){ep.onClose&&ep.onClose();}}
          style={{flex:1,background:"#f3f4f6",border:"1px solid "+C.border,color:C.muted,borderRadius:8,padding:"10px 0",fontWeight:700,cursor:"pointer",fontSize:12}}>
          Cancel
        </button>
      </div>
    </div>
  );
}

// ─── ACCESS CONTROL TAB ──────────────────────────────────────
function AccessControlTab(props){
  var usersConfig=props.usersConfig;
  var saveUsersConfig=props.saveUsersConfig;
  var sectionLabels=props.sectionLabels||{};
  var allSections=props.allSections||[];
  var users=Array.isArray(usersConfig.users)?usersConfig.users:[];

  var [editUser,setEditUser]=useState(null);
  var [msg,setMsg]=useState("");

  // All sections with labels
  var sections=allSections.map(function(id){return {id:id,label:sectionLabels[id]||id};});

  function saveUser(updatedUser,oldId){
    var searchId=oldId||updatedUser.id;
    var newUsers=users.map(function(u){return u.id===searchId?updatedUser:u;});
    saveUsersConfig(Object.assign({},usersConfig,{users:newUsers}));
    setEditUser(null);
    setMsg("Saved! ID: "+updatedUser.id+" | Staff ko logout/login karna hoga.");
    setTimeout(function(){setMsg("");},4000);
  }

  function addStaff(){
    var id="staff"+Date.now();
    var newU={id:id,name:"New Staff",password:"pass123",role:"staff",tabs:["bookings","queries"]};
    var newUsers=users.concat([newU]);
    saveUsersConfig(Object.assign({},usersConfig,{users:newUsers}));
    setEditUser(newU);
  }

  function delStaff(id){
    if(!window.confirm("Delete this staff?")) return;
    saveUsersConfig(Object.assign({},usersConfig,{users:users.filter(function(u){return u.id!==id;})}));
  }




  return(
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14,flexWrap:"wrap",gap:8}}>
        <div>
          <h2 style={{margin:0,fontSize:16,fontWeight:800,color:C.accent}}>⚙️ Access Control</h2>
          <div style={{color:C.muted,fontSize:11,marginTop:2}}>Staff IDs, passwords aur section access manage karein</div>
        </div>
        <button onClick={addStaff}
          style={{background:C.accent,color:"#fff",border:"none",borderRadius:8,padding:"8px 16px",fontWeight:800,cursor:"pointer",fontSize:13}}>
          + Add Staff
        </button>
      </div>

      {msg&&<div style={{background:"#dcfce7",border:"1px solid "+C.border,borderRadius:8,padding:"10px 14px",marginBottom:12,color:C.accent,fontWeight:700,fontSize:12}}>✅ {msg}</div>}

      {/* Edit panel */}
      {editUser&&<UserEditor user={editUser} saveUser={saveUser} delStaff={delStaff} sections={sections} sectionLabels={sectionLabels} onClose={function(){setEditUser(null);}}/>}

      {/* Users list */}
      <div style={{display:"flex",flexDirection:"column",gap:10}}>
        {users.map(function(u){
          var isAdmin=u.role==="admin";
          var tabs=Array.isArray(u.tabs)?u.tabs:[];
          return(
            <div key={u.id} style={{background:"#fff",border:"1.5px solid "+(editUser&&editUser.id===u.id?C.accent:C.border),borderRadius:12,padding:16,boxShadow:C.shadow}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
                <div style={{display:"flex",alignItems:"center",gap:10}}>
                  <div style={{background:isAdmin?"#fef9c3":C.accentSoft,border:"1.5px solid "+(isAdmin?"#fde68a":C.border),borderRadius:8,padding:"4px 10px",fontSize:11,fontWeight:700,color:isAdmin?C.gold:C.accent}}>
                    {isAdmin?"🔑 Admin":"👤 Staff"}
                  </div>
                  <div>
                    <div style={{fontWeight:800,fontSize:14}}>{u.name}</div>
                    <div style={{color:C.muted,fontSize:11}}>ID: <span style={{fontFamily:"monospace",fontWeight:700}}>{u.id}</span> | Pass: <span style={{fontFamily:"monospace"}}>{u.password}</span></div>
                  </div>
                </div>
                <button onClick={function(){setEditUser(editUser&&editUser.id===u.id?null:u);}}
                  style={{background:editUser&&editUser.id===u.id?"#fee2e2":"#fffbeb",border:"1px solid "+(editUser&&editUser.id===u.id?"#fecaca":"#fde68a"),color:editUser&&editUser.id===u.id?C.red:C.gold,borderRadius:7,padding:"6px 14px",cursor:"pointer",fontWeight:700,fontSize:12}}>
                  {editUser&&editUser.id===u.id?"✕ Close":"✏️ Edit"}
                </button>
              </div>
              {!isAdmin&&(
                <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
                  {tabs.length>0?tabs.map(function(t){return(
                    <span key={t} style={{background:C.accentSoft,color:C.accent,padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700}}>{sectionLabels[t]||t}</span>
                  );}):(<span style={{color:C.muted,fontSize:11}}>Koi access nahi</span>)}
                </div>
              )}
              {isAdmin&&<div style={{color:C.muted,fontSize:11}}>✅ Sab sections ka access</div>}
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ─── STAFF EXPENSES TAB ──────────────────────────────────────
function StaffExpTab(props){
  var staffExp=Array.isArray(props.staffExp)?props.staffExp:[];
  var setStaffExp=props.setStaffExp;
  var currentUser=props.currentUser||{};
  var expenses=Array.isArray(props.expenses)?props.expenses:[];
  var setE=props.setE;
  var isAdmin=currentUser.role==="admin";

  // Staff sees only their own, Admin sees all
  var visible=isAdmin?staffExp:staffExp.filter(function(e){return e.staffId===currentUser.id;});
  var sorted=visible.slice().sort(function(a,b){return new Date(b.date)-new Date(a.date);});

  var emptyE={id:"",staffId:"",staffName:"",date:new Date().toISOString().split("T")[0],
    description:"",category:"General",amount:"",notes:""};
  var [showForm,setShowForm]=useState(false);
  var [form,setForm]=useState(emptyE);

  var CATS=["General","Transport","Food","Office Supplies","Marketing","Utilities","Other"];

  var totalMine=staffExp.filter(function(e){return e.staffId===currentUser.id;}).reduce(function(s,e){return s+Number(e.amount||0);},0);
  var totalAll=staffExp.reduce(function(s,e){return s+Number(e.amount||0);},0);

  function saveEntry(){
    if(!form.description||!form.amount)return;
    var entry=Object.assign({},form,{
      id:form.id||uid("SE"),
      staffId:currentUser.id,
      staffName:currentUser.name,
      amount:Number(form.amount)
    });
    var updated=form.id?staffExp.map(function(x){return x.id===entry.id?entry:x;}):staffExp.concat([entry]);
    setStaffExp(updated);
    // Auto-add to main expenses
    if(!form.id){
      var mainExp={
        id:uid("E"),
        description:"["+currentUser.name+"] "+entry.description,
        category:entry.category,
        date:entry.date,
        amount:entry.amount,
        account:"Staff",
        notes:entry.notes||"",
        staffRef:entry.id
      };
      setE(expenses.concat([mainExp]));
    }
    setForm(emptyE);setShowForm(false);
  }

  function delEntry(id){
    if(window.confirm("Delete?"))
      setStaffExp(staffExp.filter(function(x){return x.id!==id;}));
  }

  return(
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12,flexWrap:"wrap",gap:8}}>
        <div>
          <h2 style={{margin:0,fontSize:16,fontWeight:800,color:C.accent}}>Staff Expenses</h2>
          <div style={{color:C.muted,fontSize:11,marginTop:2}}>
            {isAdmin?"Sab staff ki entries":"Aapki entries — "+currentUser.name}
          </div>
        </div>
        <button onClick={function(){setForm(emptyE);setShowForm(true);}}
          style={{background:C.accent,color:"#fff",border:"none",borderRadius:8,padding:"8px 16px",fontWeight:800,cursor:"pointer",fontSize:13}}>
          + Add Expense
        </button>
      </div>

      {/* Summary cards */}
      <div style={{display:"flex",gap:10,marginBottom:14,flexWrap:"wrap"}}>
        {isAdmin?(
          <>
            <div style={{flex:1,background:"#fee2e2",border:"1.5px solid #fecaca",borderRadius:12,padding:"12px 14px",textAlign:"center"}}>
              <div style={{color:C.red,fontSize:10,fontWeight:700,textTransform:"uppercase",marginBottom:3}}>Total All Staff</div>
              <div style={{color:C.red,fontWeight:900,fontSize:20}}>{pkr(totalAll)}</div>
              <div style={{color:C.muted,fontSize:10}}>{staffExp.length} entries</div>
            </div>
            {/* Per staff breakdown */}
            {Object.values(staffExp.reduce(function(acc,e){
              if(!acc[e.staffId]) acc[e.staffId]={name:e.staffName,total:0,count:0};
              acc[e.staffId].total+=Number(e.amount||0);
              acc[e.staffId].count++;
              return acc;
            },{})).map(function(s,i){return(
              <div key={i} style={{flex:1,background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:12,padding:"12px 14px",textAlign:"center"}}>
                <div style={{color:C.accent,fontSize:10,fontWeight:700,marginBottom:3}}>{s.name}</div>
                <div style={{color:C.accent,fontWeight:900,fontSize:18}}>{pkr(s.total)}</div>
                <div style={{color:C.muted,fontSize:10}}>{s.count} entries</div>
              </div>
            );})}
          </>
        ):(
          <div style={{flex:1,background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:12,padding:"12px 14px",textAlign:"center"}}>
            <div style={{color:C.accent,fontSize:10,fontWeight:700,textTransform:"uppercase",marginBottom:3}}>Meri Total Expenses</div>
            <div style={{color:C.accent,fontWeight:900,fontSize:22}}>{pkr(totalMine)}</div>
            <div style={{color:C.muted,fontSize:10}}>{staffExp.filter(function(e){return e.staffId===currentUser.id;}).length} entries</div>
          </div>
        )}
      </div>

      {/* Form Modal */}
      {showForm&&(
        <Modal title="Staff Expense Entry" onClose={function(){setShowForm(false);}}>
          <div style={{display:"flex",flexWrap:"wrap",justifyContent:"space-between"}}>
            <Field label="Description" value={form.description} onChange={function(v){setForm(Object.assign({},form,{description:v}));}} />
            <Field label="Category" value={form.category} onChange={function(v){setForm(Object.assign({},form,{category:v}));}} options={CATS} half={true}/>
            <Field label="Amount (PKR)" value={form.amount} onChange={function(v){setForm(Object.assign({},form,{amount:v}));}} type="number" half={true}/>
            <Field label="Date" value={form.date} onChange={function(v){setForm(Object.assign({},form,{date:v}));}} type="date" half={true}/>
            <Field label="Notes (optional)" value={form.notes||""} onChange={function(v){setForm(Object.assign({},form,{notes:v}));}} rows={2}/>
          </div>
          <div style={{background:C.accentSoft,borderRadius:8,padding:"8px 12px",marginBottom:12,fontSize:11,color:C.muted}}>
            ℹ️ Yeh entry automatically main Expenses mein bhi add ho jaayegi
          </div>
          <button onClick={saveEntry}
            style={{width:"100%",background:C.accent,color:"#fff",border:"none",borderRadius:8,padding:"11px 0",fontWeight:800,cursor:"pointer",fontSize:14}}>
            Save Expense
          </button>
        </Modal>
      )}

      {/* List */}
      <div style={{background:C.white,border:"1.5px solid "+C.border,borderRadius:14,overflow:"auto",boxShadow:C.shadow}}>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:12,minWidth:600}}>
          <thead><tr style={{background:C.accentSoft}}>
            {(isAdmin?["Date","Staff","Description","Category","Amount","Notes","Actions"]:["Date","Description","Category","Amount","Notes","Actions"]).map(function(h){
              return <th key={h} style={{padding:"9px 11px",textAlign:"left",color:C.accent,fontWeight:800,fontSize:10,textTransform:"uppercase"}}>{h}</th>;
            })}
          </tr></thead>
          <tbody>
            {sorted.map(function(e,i){return(
              <tr key={e.id} style={{borderTop:"1px solid "+C.border,background:i%2===0?"#fff":"#fafffe"}}>
                <td style={{padding:"8px 11px",color:C.muted,fontSize:11}}>{e.date}</td>
                {isAdmin&&<td style={{padding:"8px 11px"}}>
                  <span style={{background:C.accentSoft,color:C.accent,padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700}}>{e.staffName}</span>
                </td>}
                <td style={{padding:"8px 11px",fontWeight:600}}>{e.description}</td>
                <td style={{padding:"8px 11px",color:C.muted,fontSize:11}}>{e.category}</td>
                <td style={{padding:"8px 11px",color:C.red,fontWeight:800}}>{pkr(e.amount)}</td>
                <td style={{padding:"8px 11px",color:C.muted,fontSize:11}}>{e.notes||"--"}</td>
                <td style={{padding:"8px 11px"}}>
                  <div style={{display:"flex",gap:4}}>
                    <button onClick={function(){setForm(Object.assign({},e));setShowForm(true);}}
                      style={{background:"#fffbeb",border:"1px solid #fde68a",color:C.gold,borderRadius:5,padding:"3px 7px",cursor:"pointer",fontSize:10,fontWeight:700}}>Edit</button>
                    {(isAdmin||e.staffId===currentUser.id)&&
                      <button onClick={function(){delEntry(e.id);}}
                        style={{background:C.redBg,border:"1px solid #fecaca",color:C.red,borderRadius:5,padding:"3px 7px",cursor:"pointer",fontSize:10,fontWeight:700}}>Del</button>}
                  </div>
                </td>
              </tr>
            );})}
            {sorted.length===0&&<tr><td colSpan={7} style={{padding:"20px",textAlign:"center",color:C.muted}}>Koi entry nahi — + Add Expense click karein</td></tr>}
          </tbody>
        </table>
      </div>
    </div>
  );
}

